// C3: Physical sensing components
instance InputCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor that provides the motor input current I_M"
    DTDFVocab:producedData InputCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Encoder sensor measuring motor shaft angular position"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Encoder sensor measuring gearbox output angular position"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance InputCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom InputCurrentSensor
]

instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// C10: Data instances
instance InputCurrentData : DTDFVocab:Data [
    base:desc "Raw motor input current I_M streamed via MQTT"
    DTDFVocab:fromData InputCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

instance MotorEncoderAngleData : DTDFVocab:Data [
    base:desc "Angular position from motor encoder"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

instance GearboxEncoderAngleData : DTDFVocab:Data [
    base:desc "Angular position from gearbox encoder"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Torque τ derived from encoder positions"
    DTDFVocab:inputTo SimulinkEnabler
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity ω derived from encoder positions"
    DTDFVocab:inputTo SimulinkEnabler
]

instance AngularAccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration derived from encoder positions"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulatedTorqueData : DTDFVocab:Data [
    base:desc "Torque simulated by Simulink friction models"
    DTDFVocab:inputTo DashboardEnabler
]

instance SimulatedVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity simulated by Simulink friction models"
    DTDFVocab:inputTo DashboardEnabler
]

// C11: Enablers
instance MQTTEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker used for publishing live sensor streams"
