]

instance DataComparisonService : DTDFVocab:Service [
    base:desc "Comparison of measured torque/velocity with Simulink simulated results"
    DTDFVocab:provides MotionAccuracyInsight
]

instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Visualization of measured vs simulated data and identified friction parameters"
    DTDFVocab:provides RealTimeFrictionIdentificationInsight
